8,0.02406283,-0.03022800,0.04416825,-0.00135524,0.01155299,0.06718595,0.06923949,0.03182879,-0.05895885,0.05485715,-0.02216491,0.02394436,-0.06228910,0.05786870,-0.05696996,-0.02351184,-0.03674476,-0.03331368,0.02410545,0.04115681,-0.05276197,0.03570683,-0.07888912,-0.02015051,-0.05002591,0.00972519,-0.02662754,-0.01492273,-0.08722290,-0.03784321,-0.00913298,0.02417859,0.03693119,0.02536058,-0.06596409,-0.07030846,-0.01933370,-0.02796625,-0.00438802,-0.02960243,0.04672133,-0.01011399]',E'Using the `CookieCsrfTokenRepository`\n\n[[csrf-token-repository-cookie-configuration]]\n.Configure `CookieCsrfTokenRepository`\n[tabs]\n======\nJava::\n+\n[source,java,role="primary"]\n----\n@Configuration\n@EnableWebSecurity\npublic class SecurityConfig {\n\n	@Bean\n	public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {\n		http\n			// ...\n			.csrf((csrf) -> csrf\n				.csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())\n			);\n		return http.build();\n	}\n}\n----','{"source": "spring-security", "version": "7", "language": "java", "title": "Csrf.Adoc", "section_title": "csrf.adoc", "url": "https://github.com/spring-projects/spring-security/blob/main/docs/modules/ROOT/pages/servlet/exploits/csrf.adoc", "topics": "spring,security,csrf.adoc", "categories": "java,security,auth,oauth2"}');
