07335,-0.00104403,0.00622267,0.01662467,0.01683733,-0.00069152,0.04665799,0.05163814,0.03559382,-0.05196966,0.08239748,-0.01041922,0.01168040,-0.05722930,0.06289376,-0.05048729,-0.01748948,-0.04054799,-0.03937009,0.01166864,0.07775478,-0.01335887,0.05390789,-0.07618354,-0.05036504,-0.00955159,0.06838261,-0.03334946,-0.02745219,-0.06221966,-0.03940364,-0.00484487,0.05063030,0.05993271,-0.00060748,-0.03445882,-0.03807982,0.01220354,-0.02348214,-0.00741592,-0.02713507,0.04734710,0.01428411]',E'Using the `CsrfTokenRequestAttributeHandler`\n\n.Opt-out of BREACH protection\n[tabs]\n======\nJava::\n+\n[source,java,role="primary"]\n----\n@Configuration\n@EnableWebSecurity\npublic class SecurityConfig {\n\n	@Bean\n	public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {\n		http\n			// ...\n			.csrf((csrf) -> csrf\n				.csrfTokenRequestHandler(new CsrfTokenRequestAttributeHandler())\n			);\n		return http.build();\n	}\n}\n----','{"source": "spring-security", "version": "7", "language": "java", "title": "Csrf.Adoc", "section_title": "csrf.adoc", "url": "https://github.com/spring-projects/spring-security/blob/main/docs/modules/ROOT/pages/servlet/exploits/csrf.adoc", "topics": "spring,security,csrf.adoc", "categories": "java,security,auth,oauth2"}');
